     1→// Phase 5: TypeChecker - 정적 타입 검증
     2→
     3→import { Expr, Stmt, Program } from "./ast"
     4→import {
     5→  Type,
     6→  PrimitiveType,
     7→  TypeCheckError,
     8→  TypeCheckResult,
     9→  typesCompatible,
    10→  typeToString,
    11→  getOperationResultType,
    12→  inferTypeFromValue,
    13→  BUILTIN_TYPES,
    14→} from "./type-system"
    15→
    16→/**
    17→ * TypeChecker: AST 기반 정적 타입 검증
    18→ */
    19→export class TypeChecker {
    20→  private env: Map<string, Type> = new Map()
    21→  private functionTypes: Map<string, Type> = new Map()
    22→  private errors: TypeCheckError[] = []
    23→  private currentFunctionReturnTypes: Type[] = []
    24→
    25→  /**
    26→   * 전체 프로그램 타입 검사
    27→   */
    28→  public check(program: Program): TypeCheckResult {
    29→    this.errors = []
    30→    this.env.clear()
    31→    this.functionTypes.clear()
    32→
    33→    // First pass: 함수 정의 수집
    34→    for (const stmt of program.stmts) {
    35→      if (stmt.kind === "fn") {
    36→        this.registerFunctionType(stmt)
    37→      }
    38→    }
    39→
    40→    // Second pass: 함수 본문 및 다른 명령문 검사
    41→    for (const stmt of program.stmts) {
    42→      this.checkStmt(stmt)
    43→    }
    44→
    45→    return {
    46→      success: this.errors.length === 0,
    47→      errors: this.errors,
    48→      types: new Map(this.env),
    49→    }
    50→  }
    51→
    52→  /**
    53→   * 수집된 return 타입들로부터 함수의 반환 타입 추론
    54→   */
    55→  private inferReturnType(types: Type[]): Type {
    56→    if (types.length === 0) return BUILTIN_TYPES.UNKNOWN
    57→    const first = types[0]
    58→    if (types.every(t => JSON.stringify(t) === JSON.stringify(first)))
    59→      return first
    60→    return BUILTIN_TYPES.UNKNOWN
    61→  }
    62→
    63→  /**
    64→   * 함수 타입 등록
    65→   */
    66→  private registerFunctionType(stmt: Stmt): void {
    67→    if (stmt.kind === "fn") {
    68→      const fnStmt = stmt as any
    69→      const paramTypes: Type[] = (fnStmt.params || []).map(() => ({
    70→        kind: "primitive" as const,
    71→        type: PrimitiveType.UNKNOWN,
    72→      }))
    73→
    74→      const returnType: Type = {
    75→        kind: "primitive",
    76→        type: PrimitiveType.UNKNOWN,
    77→      }
    78→
    79→      const fnType: Type = {
    80→        kind: "fn",
    81→        paramTypes,
    82→        returnType,
    83→      }
    84→
    85→      this.functionTypes.set(fnStmt.name, fnType)
    86→    }
    87→  }
    88→
    89→  /**
    90→   * 명령문 타입 검사
    91→   */
    92→  private checkStmt(stmt: Stmt): void {
    93→    switch (stmt.kind) {
    94→      case "print": {
    95→        const printStmt = stmt as any
    96→        this.checkExpr(printStmt.expr)
    97→        break
    98→      }
    99→
   100→      case "expr": {
   101→        const exprStmt = stmt as any
   102→        this.checkExpr(exprStmt.expr)
   103→        break
   104→      }
   105→
   106→      case "let": {
   107→        const letStmt = stmt as any
   108→        if (letStmt.init) {
   109→          const valueType = this.checkExpr(letStmt.init)
   110→          this.env.set(letStmt.name, valueType)
   111→        } else {
   112→          this.env.set(letStmt.name, BUILTIN_TYPES.UNKNOWN)
   113→        }
   114→        break
   115→      }
   116→
   117→      case "fn": {
   118→        const fnStmt = stmt as any
   119→        const savedEnv = new Map(this.env)
   120→        const savedReturnTypes = this.currentFunctionReturnTypes
   121→
   122→        this.currentFunctionReturnTypes = []
   123→
   124→        // 파라미터를 환경에 추가
   125→        for (const param of fnStmt.params || []) {
   126→          this.env.set(param, {
   127→            kind: "primitive",
   128→            type: PrimitiveType.UNKNOWN,
   129→          })
   130→        }
   131→
   132→        // 함수 본문 검사
   133→        for (const s of fnStmt.body || []) {
   134→          this.checkStmt(s)
   135→        }
   136→
   137→        // return 타입 추론 후 functionTypes 갱신
   138→        const inferredReturn = this.inferReturnType(
   139→          this.currentFunctionReturnTypes
   140→        )
   141→        const existingFnType = this.functionTypes.get(fnStmt.name)
   142→        if (existingFnType && existingFnType.kind === "fn") {
   143→          this.functionTypes.set(fnStmt.name, {
   144→            kind: "fn",
   145→            paramTypes: existingFnType.paramTypes,
   146→            returnType: inferredReturn,
   147→          })
   148→        }
   149→
   150→        this.currentFunctionReturnTypes = savedReturnTypes
   151→        this.env = savedEnv
   152→        break
   153→      }
   154→
   155→      case "if": {
   156→        const ifStmt = stmt as any
   157→        this.checkExpr(ifStmt.cond)
   158→        for (const s of ifStmt.then || []) {
   159→          this.checkStmt(s)
   160→        }
   161→        if (ifStmt.else) {
   162→          for (const s of ifStmt.else) {
   163→            this.checkStmt(s)
   164→          }
   165→        }
   166→        break
   167→      }
   168→
   169→      case "for": {
   170→        const forStmt = stmt as any
   171→        this.checkExpr(forStmt.iter)
   172→        // 루프 변수를 환경에 추가
   173→        this.env.set(forStmt.name, BUILTIN_TYPES.UNKNOWN)
   174→        for (const s of forStmt.body || []) {
   175→          this.checkStmt(s)
   176→        }
   177→        break
   178→      }
   179→
   180→      case "while": {
   181→        const whileStmt = stmt as any
   182→        this.checkExpr(whileStmt.cond)
   183→        for (const s of whileStmt.body || []) {
   184→          this.checkStmt(s)
   185→        }
   186→        break
   187→      }
   188→
   189→      case "return": {
   190→        const returnStmt = stmt as any
   191→        if (returnStmt.value) {
   192→          const retType = this.checkExpr(returnStmt.value)
   193→          this.currentFunctionReturnTypes.push(retType)
   194→        }
   195→        break
   196→      }
   197→
   198→      case "block": {
   199→        const blockStmt = stmt as any
   200→        for (const s of blockStmt.body || []) {
   201→          this.checkStmt(s)
   202→        }
   203→        break
   204→      }
   205→
   206→      case "try": {
   207→        const tryStmt = stmt as any
   208→        for (const s of tryStmt.body || []) {
   209→          this.checkStmt(s)
   210→        }
   211→        if (tryStmt.catchVar) {
   212→          this.env.set(tryStmt.catchVar, BUILTIN_TYPES.UNKNOWN)
   213→        }
   214→        for (const s of tryStmt.catchBody || []) {
   215→          this.checkStmt(s)
   216→        }
   217→        for (const s of tryStmt.finallyBody || []) {
   218→          this.checkStmt(s)
   219→        }
   220→        break
   221→      }
   222→
   223→      case "throw": {
   224→        const throwStmt = stmt as any
   225→        this.checkExpr(throwStmt.expr)
   226→        break
   227→      }
   228→
   229→      case "if-let": {
   230→        const ifLetStmt = stmt as any
   231→        this.checkExpr(ifLetStmt.value)
   232→        // 패턴 바인딩
   233→        if (ifLetStmt.pattern.kind === "ident") {
   234→          this.env.set(ifLetStmt.pattern.name, BUILTIN_TYPES.UNKNOWN)
   235→        }
   236→        for (const s of ifLetStmt.body || []) {
   237→          this.checkStmt(s)
   238→        }
   239→        if (ifLetStmt.else) {
   240→          for (const s of ifLetStmt.else) {
   241→            this.checkStmt(s)
   242→          }
   243→        }
   244→        break
   245→      }
   246→
   247→      case "while-let": {
   248→        const whileLetStmt = stmt as any
   249→        this.checkExpr(whileLetStmt.value)
   250→        if (whileLetStmt.pattern.kind === "ident") {
   251→          this.env.set(whileLetStmt.pattern.name, BUILTIN_TYPES.UNKNOWN)
   252→        }
   253→        for (const s of whileLetStmt.body || []) {
   254→          this.checkStmt(s)
   255→        }
   256→        break
   257→      }
   258→
   259→      case "match": {
   260→        const matchStmt = stmt as any
   261→        this.checkExpr(matchStmt.subject)
   262→        for (const arm of matchStmt.arms || []) {
   263→          if (arm.pattern) {
   264→            this.checkExpr(arm.pattern)
   265→          }
   266→          if (arm.guard) {
   267→            this.checkExpr(arm.guard)
   268→          }
   269→          for (const s of arm.body || []) {
   270→            this.checkStmt(s)
   271→          }
   272→        }
   273→        break
   274→      }
   275→    }
   276→  }
   277→
   278→  /**
   279→   * 표현식 타입 검사
   280→   */
   281→  public checkExpr(expr: Expr): Type {
   282→    switch (expr.kind) {
   283→      case "number":
   284→        return { kind: "primitive", type: PrimitiveType.NUM }
   285→
   286→      case "string":
   287→        return { kind: "primitive", type: PrimitiveType.STR }
   288→
   289→      case "bool":
   290→        return { kind: "primitive", type: PrimitiveType.BOOL }
   291→
   292→      case "null":
   293→        return { kind: "primitive", type: PrimitiveType.NULL }
   294→
   295→      case "ident": {
   296→        const identExpr = expr as any
   297→        const type = this.env.get(identExpr.name)
   298→        if (!type) {
   299→          this.addError(
   300→            `Undefined variable '${identExpr.name}'`,
   301→            undefined,
   302→            undefined
   303→          )
   304→          return BUILTIN_TYPES.UNKNOWN
   305→        }
   306→        return type
   307→      }
   308→
   309→      case "assign": {
   310→        const assignExpr = expr as any
   311→        const valueType = this.checkExpr(assignExpr.value)
   312→
   313→        // target이 ident인 경우 할당
   314→        if (assignExpr.target.kind === "ident") {
   315→          this.env.set(assignExpr.target.name, valueType)
   316→        }
   317→        return valueType
   318→      }
   319→
   320→      case "binary": {
   321→        const binExpr = expr as any
   322→        const leftType = this.checkExpr(binExpr.left)
   323→        const rightType = this.checkExpr(binExpr.right)
   324→
   325→        // 타입 호환성 검사
   326→        const resultType = getOperationResultType(
   327→          binExpr.op,
   328→          leftType,
   329→          rightType
   330→        )
   331→
   332→        // Add 연산 검증
   333→        if (binExpr.op === "+" || binExpr.op === "Add") {
   334→          if (leftType.kind === "primitive" && rightType.kind === "primitive") {
   335→            const left = leftType.type
   336→            const right = rightType.type
   337→
   338→            if (
   339→              !(
   340→                (left === PrimitiveType.NUM && right === PrimitiveType.NUM) ||
   341→                (left === PrimitiveType.STR || right === PrimitiveType.STR) ||
   342→                (left === PrimitiveType.UNKNOWN ||
   343→                  right === PrimitiveType.UNKNOWN)
   344→              )
   345→            ) {
   346→              this.addError(
   347→                `Cannot add ${typeToString(leftType)} and ${typeToString(rightType)}`,
   348→                undefined,
   349→                undefined,
   350→                undefined,
   351→                leftType,
   352→                rightType
   353→              )
   354→            }
   355→          }
   356→        }
   357→
   358→        return resultType
   359→      }
   360→
   361→      case "unary": {
   362→        const unaryExpr = expr as any
   363→        const operandType = this.checkExpr(unaryExpr.expr)
   364→
   365→        if (unaryExpr.op === "!") {
   366→          if (
   367→            operandType.kind !== "primitive" ||
   368→            operandType.type !== PrimitiveType.BOOL
   369→          ) {
   370→            this.addError(
   371→              `Cannot apply ! to ${typeToString(operandType)}`,
   372→              undefined,
   373→              undefined
   374→            )
   375→          }
   376→          return BUILTIN_TYPES.BOOL
   377→        }
   378→
   379→        if (unaryExpr.op === "-") {
   380→          if (
   381→            operandType.kind !== "primitive" ||
   382→            operandType.type !== PrimitiveType.NUM
   383→          ) {
   384→            this.addError(
   385→              `Cannot negate ${typeToString(operandType)}`,
   386→              undefined,
   387→              undefined
   388→            )
   389→          }
   390→          return BUILTIN_TYPES.NUM
   391→        }
   392→
   393→        return operandType
   394→      }
   395→
   396→      case "call": {
   397→        const callExpr = expr as any
   398→
   399→        // callee에서 함수 이름 추출
   400→        let fnName = ""
   401→        if (callExpr.callee.kind === "ident") {
   402→          fnName = callExpr.callee.name
   403→        }
   404→
   405→        const fnType = this.functionTypes.get(fnName)
   406→
   407→        if (!fnType) {
   408→          this.addError(
   409→            `Undefined function '${fnName}'`,
   410→            undefined,
   411→            undefined
   412→          )
   413→          return BUILTIN_TYPES.UNKNOWN
   414→        }
   415→
   416→        if (fnType.kind === "fn") {
   417→          // 인자 개수 확인
   418→          if ((callExpr.args || []).length !== fnType.paramTypes.length) {
   419→            this.addError(
   420→              `Function '${fnName}' expects ${fnType.paramTypes.length} arguments, got ${(callExpr.args || []).length}`,
   421→              undefined,
   422→              undefined
   423→            )
   424→          }
   425→
   426→          // 인자 타입 검사
   427→          for (let i = 0; i < (callExpr.args || []).length; i++) {
   428→            const argType = this.checkExpr(callExpr.args[i])
   429→            const paramType = fnType.paramTypes[i] || BUILTIN_TYPES.UNKNOWN
   430→
   431→            if (!typesCompatible(argType, paramType)) {
   432→              this.addError(
   433→                `Argument ${i} of '${fnName}': expected ${typeToString(paramType)}, got ${typeToString(argType)}`,
   434→                undefined,
   435→                undefined,
   436→                undefined,
   437→                paramType,
   438→                argType
   439→              )
   440→            }
   441→          }
   442→
   443→          return fnType.returnType
   444→        }
   445→
   446→        return BUILTIN_TYPES.UNKNOWN
   447→      }
   448→
   449→      case "array": {
   450→        const arrayExpr = expr as any
   451→        if ((arrayExpr.elements || []).length === 0) {
   452→          return {
   453→            kind: "array",
   454→            elementType: BUILTIN_TYPES.UNKNOWN,
   455→          }
   456→        }
   457→
   458→        const elementTypes = (arrayExpr.elements || []).map((e: any) =>
   459→          this.checkExpr(e)
   460→        )
   461→
   462→        // 모든 요소 타입이 같은지 확인
   463→        const firstType = elementTypes[0]
   464→        for (let i = 1; i < elementTypes.length; i++) {
   465→          if (!typesCompatible(elementTypes[i], firstType)) {
   466→            this.addError(
   467→              `Array elements have inconsistent types: ${typeToString(firstType)} and ${typeToString(elementTypes[i])}`,
   468→              undefined,
   469→              undefined
   470→            )
   471→          }
   472→        }
   473→
   474→        return {
   475→          kind: "array",
   476→          elementType: firstType,
   477→        }
   478→      }
   479→
   480→      case "index": {
   481→        const indexExpr = expr as any
   482→        const objectType = this.checkExpr(indexExpr.object)
   483→        this.checkExpr(indexExpr.index)
   484→
   485→        if (objectType.kind === "array") {
   486→          return objectType.elementType
   487→        }
   488→        return BUILTIN_TYPES.UNKNOWN
   489→      }
   490→
   491→      case "member": {
   492→        const memberExpr = expr as any
   493→        const objectType = this.checkExpr(memberExpr.object)
   494→
   495→        if (objectType.kind === "object") {
   496→          const propType = objectType.properties.get(memberExpr.property)
   497→          return propType || BUILTIN_TYPES.UNKNOWN
   498→        }
   499→        return BUILTIN_TYPES.UNKNOWN
   500→      }
   501→
   502→      case "object": {
   503→        const objExpr = expr as any
   504→        const properties = new Map<string, Type>()
   505→
   506→        for (const entry of objExpr.entries || []) {
   507→          properties.set(entry.key, this.checkExpr(entry.value))
   508→        }
   509→
   510→        return {
   511→          kind: "object",
   512→          properties,
   513→        }
   514→      }
   515→
   516→      case "fn": {
   517→        const fnExpr = expr as any
   518→        const savedEnv = new Map(this.env)
   519→        const savedReturnTypes = this.currentFunctionReturnTypes
   520→
   521→        this.currentFunctionReturnTypes = []
   522→
   523→        // 파라미터를 환경에 추가
   524→        for (const param of fnExpr.params || []) {
   525→          this.env.set(param, {
   526→            kind: "primitive",
   527→            type: PrimitiveType.UNKNOWN,
   528→          })
   529→        }
   530→
   531→        // 함수 본문 검사
   532→        for (const stmt of fnExpr.body || []) {
   533→          this.checkStmt(stmt)
   534→        }
   535→
   536→        const inferredReturn = this.inferReturnType(
   537→          this.currentFunctionReturnTypes
   538→        )
   539→        const paramTypes: Type[] = (fnExpr.params || []).map(() => ({
   540→          kind: "primitive" as const,
   541→          type: PrimitiveType.UNKNOWN,
   542→        }))
   543→
   544→        this.currentFunctionReturnTypes = savedReturnTypes
   545→        this.env = savedEnv
   546→
   547→        return {
   548→          kind: "fn",
   549→          paramTypes,
   550→          returnType: inferredReturn,
   551→        }
   552→      }
   553→
   554→      case "ternary": {
   555→        const ternaryExpr = expr as any
   556→        this.checkExpr(ternaryExpr.cond)
   557→        const thenType = this.checkExpr(ternaryExpr.then)
   558→        const elseType = this.checkExpr(ternaryExpr.else)
   559→
   560→        // then과 else 타입이 호환 가능해야 함
   561→        if (!typesCompatible(thenType, elseType)) {
   562→          this.addError(
   563→            `Ternary branch types incompatible: ${typeToString(thenType)} vs ${typeToString(elseType)}`,
   564→            undefined,
   565→            undefined
   566→          )
   567→        }
   568→
   569→        return thenType
   570→      }
   571→
   572→      case "if": {
   573→        const ifExpr = expr as any
   574→        this.checkExpr(ifExpr.cond)
   575→        for (const s of ifExpr.then || []) {
   576→          this.checkStmt(s)
   577→        }
   578→        for (const s of ifExpr.else || []) {
   579→          this.checkStmt(s)
   580→        }
   581→        return BUILTIN_TYPES.UNKNOWN
   582→      }
   583→
   584→      case "match": {
   585→        const matchExpr = expr as any
   586→        this.checkExpr(matchExpr.subject)
   587→        for (const arm of matchExpr.arms || []) {
   588→          if (arm.pattern) {
   589→            this.checkExpr(arm.pattern)
   590→          }
   591→          if (arm.guard) {
   592→            this.checkExpr(arm.guard)
   593→          }
   594→          for (const s of arm.body || []) {
   595→            this.checkStmt(s)
   596→          }
   597→        }
   598→        return BUILTIN_TYPES.UNKNOWN
   599→      }
   600→
   601→      default:
   602→        return BUILTIN_TYPES.UNKNOWN
   603→    }
   604→  }
   605→
   606→  /**
   607→   * 오류 추가
   608→   */
   609→  private addError(
   610→    message: string,
   611→    line?: number,
   612→    column?: number,
   613→    variable?: string,
   614→    expected?: Type,
   615→    actual?: Type
   616→  ): void {
   617→    this.errors.push({
   618→      message,
   619→      line,
   620→      column,
   621→      variable,
   622→      expected,
   623→      actual,
   624→    })
   625→  }
   626→
   627→  /**
   628→   * 환경 조회
   629→   */
   630→  public getEnv(): Map<string, Type> {
   631→    return new Map(this.env)
   632→  }
   633→
   634→  /**
   635→   * 함수 타입 조회
   636→   */
   637→  public getFunctionType(name: string): Type | undefined {
   638→    return this.functionTypes.get(name)
   639→  }
   640→
   641→  /**
   642→   * 오류 개수
   643→   */
   644→  public getErrorCount(): number {
   645→    return this.errors.length
   646→  }
   647→
   648→  /**
   649→   * 오류 목록
   650→   */
   651→  public getErrors(): TypeCheckError[] {
   652→    return [...this.errors]
   653→  }
   654→}
