     1→// Phase 5: 타입 시스템 기본 정의
     2→
     3→/**
     4→ * Primitive 타입
     5→ */
     6→export enum PrimitiveType {
     7→  NUM = "num",
     8→  STR = "str",
     9→  BOOL = "bool",
    10→  NULL = "null",
    11→  UNKNOWN = "unknown",
    12→}
    13→
    14→/**
